import { useState, useEffect, useCallback, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../../context/AuthContext";
import API from "../../api";

export default function WaiterPanel() {
  const [tables, setTables] = useState([]);
  const [menu, setMenu] = useState([]);
  const [selectedTable, setSelectedTable] = useState(null);
  const [allRounds, setAllRounds] = useState([]);
  const [draftRoundIdx, setDraftRoundIdx] = useState(null);
  const [view, setView] = useState("tables");
  const [loading, setLoading] = useState(true);

  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const summaryRef = useRef(null);

  /* ---------------- LOAD ---------------- */
  const loadData = useCallback(async () => {
    try {
      const [t, m] = await Promise.all([
        API.get("/tables"),
        API.get("/menu"),
      ]);
      setTables(t.data);
      setMenu(m.data.filter(i => i.is_available));
    } catch {}
    setLoading(false);
  }, []);

  useEffect(() => { loadData(); }, [loadData]);

  /* ---------------- ACTIONS ---------------- */
  const selectTable = async (table) => {
    setSelectedTable(table);
    setView("order");
  };

  const startOrder = async () => {
    const res = await API.post("/orders", { table_id: selectedTable.id });
    setAllRounds([{ order: res.data, items: [] }]);
    setDraftRoundIdx(0);
  };

  const addItem = async (item) => {
    if (draftRoundIdx === null) return;
    const round = allRounds[draftRoundIdx];

    await API.post(`/orders/${round.order.id}/items`, {
      menu_id: item.id,
      quantity: 1,
      unit_price: item.price,
    });

    const detail = await API.get(`/orders/${round.order.id}`);
    const updated = [...allRounds];
    updated[draftRoundIdx] = {
      ...updated[draftRoundIdx],
      items: detail.data.items,
      order: detail.data.order,
    };
    setAllRounds(updated);
  };

  const goBack = () => {
    setView("tables");
    setSelectedTable(null);
    setAllRounds([]);
    setDraftRoundIdx(null);
  };

  const handleLogout = async () => {
    await API.post("/auth/logout");
    logout();
    navigate("/");
  };

  /* ---------------- UI ---------------- */
  return (
    <div style={{ minHeight: "100vh", background: "#f1f5f9" }}>

      {/* HEADER */}
      <div style={{
        padding: "16px 24px",
        background: "linear-gradient(135deg,#4f46e5,#7c3aed)",
        color: "#fff",
        display: "flex",
        justifyContent: "space-between",
        alignItems: "center"
      }}>
        <div>
          <div style={{ fontWeight: 800 }}>🍽️ Waiter Panel</div>
          <div style={{ fontSize: 12 }}>{user?.name}</div>
        </div>

        <div style={{ display: "flex", gap: 10 }}>
          {view === "order" && (
            <button onClick={goBack} className="btn">← Back</button>
          )}
          <button onClick={handleLogout} className="btn">Logout</button>
        </div>
      </div>

      <div style={{ padding: 20 }}>

        {/* TABLE VIEW */}
        {view === "tables" && (
          <>
            <h2 style={{ marginBottom: 20 }}>Select Table</h2>

            {loading ? "Loading..." : (
              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fill,minmax(160px,1fr))",
                gap: 16
              }}>
                {tables.map(t => (
                  <div
                    key={t.id}
                    onClick={() => selectTable(t)}
                    style={{
                      padding: 20,
                      borderRadius: 16,
                      cursor: "pointer",
                      background:
                        t.status === "occupied"
                          ? "linear-gradient(135deg,#fecaca,#f87171)"
                          : "linear-gradient(135deg,#bbf7d0,#4ade80)",
                      boxShadow: "0 10px 25px rgba(0,0,0,0.1)",
                      transition: "0.2s"
                    }}
                  >
                    <div style={{ fontSize: 20, fontWeight: 800 }}>
                      Table {t.table_number}
                    </div>
                    <div>{t.status}</div>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {/* ORDER VIEW */}
        {view === "order" && (
          <div style={{
            display: "grid",
            gridTemplateColumns: "1fr 350px",
            gap: 20
          }}>

            {/* MENU */}
            <div>
              <h3>Menu</h3>

              {allRounds.length === 0 && (
                <button onClick={startOrder} className="btn-primary">
                  Start Order
                </button>
              )}

              <div style={{
                display: "grid",
                gridTemplateColumns: "repeat(auto-fill,minmax(140px,1fr))",
                gap: 12,
                marginTop: 16
              }}>
                {menu.map(item => (
                  <div
                    key={item.id}
                    onClick={() => addItem(item)}
                    style={{
                      padding: 14,
                      borderRadius: 14,
                      background: "#fff",
                      boxShadow: "0 6px 14px rgba(0,0,0,0.08)",
                      cursor: "pointer"
                    }}
                  >
                    <div style={{ fontWeight: 600 }}>{item.name}</div>
                    <div style={{ color: "#10b981" }}>
                      Rs. {item.price}
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* SUMMARY */}
            <div style={{
              background: "#fff",
              borderRadius: 16,
              padding: 16,
              boxShadow: "0 10px 30px rgba(0,0,0,0.1)"
            }}>
              <h3>Order Summary</h3>

              {allRounds.map((r, idx) => (
                <div key={idx} style={{ marginBottom: 12 }}>
                  <strong>Round {idx + 1}</strong>

                  {r.items.map(it => (
                    <div key={it.id} style={{
                      display: "flex",
                      justifyContent: "space-between"
                    }}>
                      <span>{it.name}</span>
                      <span>Rs. {it.price}</span>
                    </div>
                  ))}
                </div>
              ))}

              <hr />

              <div style={{
                fontWeight: 800,
                fontSize: 18,
                textAlign: "right"
              }}>
                Total: Rs.{" "}
                {allRounds.reduce((s, r) => s + (r.order?.total || 0), 0)}
              </div>
            </div>
          </div>
        )}

      </div>

      {/* BASIC STYLES */}
      <style>{`
        .btn {
          padding: 8px 12px;
          border-radius: 8px;
          border: none;
          cursor: pointer;
        }

        .btn-primary {
          padding: 10px 16px;
          background: linear-gradient(135deg,#4f46e5,#7c3aed);
          color: #fff;
          border: none;
          border-radius: 10px;
          font-weight: 700;
          cursor: pointer;
        }

        .btn:hover {
          transform: translateY(-2px);
        }
      `}</style>
    </div>
  );
}
